import pytest

def test_hr_admin_can_view_training_course_returns_200_with_entity_id(
    hr_admin_token, api_client, existing_course_id, audit_checker
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    resp = api_client.get(
        f"/api/training-courses/{existing_course_id}",
        headers=headers
    )
    assert resp.status_code in (200, 201), (
        f"Expected 200/201, got {resp.status_code}"
    )
    body = resp.json()
    assert str(body.get("id")) == str(existing_course_id), (
        "Entity id in response does not match requested course id"
    )
    assert audit_checker.record_exists(
        action="view",
        resource="training-course",
        resource_id=existing_course_id
    ), "Audit record was not written after successful view"

