def test_unauthenticated_request_to_view_training_course_returns_401(
    api_client, existing_course_id, audit_checker
):
    resp = api_client.get(
        f"/api/training-courses/{existing_course_id}"
    )
    assert resp.status_code == 401, (
        f"Expected 401 for unauthenticated request, got {resp.status_code}"
    )
    body = resp.json()
    assert "error" in body or "detail" in body, (
        "Response body should contain an error descriptor"
    )
    assert not audit_checker.record_exists(
        action="view",
        resource="training-course",
        resource_id=existing_course_id
    ), "Audit record must NOT be written for unauthenticated access"

