def test_view_training_course_missing_mandatory_field_returns_400(
    hr_admin_token, api_client, audit_checker
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    # Omit mandatory 'courseId' query param to trigger validation error
    resp = api_client.get(
        "/api/training-courses",
        headers=headers,
        params={}  # explicitly empty - mandatory param absent
    )
    assert resp.status_code == 400, (
        f"Expected 400 for missing mandatory field, got {resp.status_code}"
    )
    body = resp.json()
    assert "error" in body or "detail" in body or "errors" in body, (
        "Response body should describe the validation error"
    )
    assert not audit_checker.record_exists(
        action="view",
        resource="training-course",
        resource_id=None
    ), "Audit record must NOT be written on validation failure"

import pytest

def test_audit_record_written_only_after_successful_view_state_transition(
    hr_admin_token, api_client, existing_course_id, audit_checker
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    count_before = audit_checker.count_records(
        action="view",
        resource="training-course",
        resource_id=existing_course_id
    )
    resp = api_client.get(
        f"/api/training-courses/{existing_course_id}",
        headers=headers
    )
    assert resp.status_code in (200, 201), (
        f"Expected 200/201, got {resp.status_code}"
    )
    count_after = audit_checker.count_records(
        action="view",
        resource="training-course",
        resource_id=existing_course_id
    )
    assert count_after == count_before + 1, (
        f"Audit count should increment by 1: before={count_before}, after={count_after}"
    )
